INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- ============================================================================
-- SUBTOPIC 1: Declarative Sentences (30 questions)
-- ============================================================================

-- EASY (12 questions)
('foundation', 'sentence-types', 'beginner', 'Which is a declarative sentence?', '["I love music.", "Do you love music?", "Love music!", "What beautiful music!"]', 0, 'Declarative sentence: makes a statement, ends with period. "I love music." = statement. Pattern: subject + verb + object.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Declarative sentences end with:', '["period (.)", "question mark (?)", "exclamation mark (!)", "comma (,)"]', 0, 'Declarative sentences: end with period. Make statements or give information. Pattern: Statement + period.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which makes a statement?', '["She is a teacher.", "Is she a teacher?", "Be a teacher!", "What a teacher!"]', 0, 'Declarative: makes statement. "She is a teacher." = statement of fact. Pattern: Subject + verb + complement.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"The sun rises in the east." This is:', '["Declarative", "Interrogative", "Imperative", "Exclamatory"]', 0, 'Declarative sentence: states a fact, ends with period. Gives information without asking or commanding.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Declarative sentences:', '["make statements", "ask questions", "give commands", "show strong emotion"]', 0, 'Declarative sentences: make statements, give information, express opinions. Most common sentence type in English.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which is declarative?', '["I study English daily.", "Do you study English?", "Study English!", "How wonderful English is!"]', 0, 'Declarative: statement. "I study English daily." = states what I do. Pattern: Simple statement + period.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"My brother lives in Delhi." Type?', '["Declarative", "Interrogative", "Imperative", "Exclamatory"]', 0, 'Declarative: makes statement about brother. Pattern: Subject + verb + prepositional phrase + period.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Correct punctuation for statement:', '["period (.)", "question mark (?)", "exclamation mark (!)", "semicolon (;)"]', 0, 'Statements (declarative sentences) end with period. Question = ?, exclamation = !, statement = period.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which gives information?', '["Water boils at 100°C.", "Does water boil?", "Boil the water!", "How hot the water is!"]', 0, 'Declarative: gives information/facts. States scientific fact. Pattern: Subject + verb + complement + period.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"She sings beautifully." Type?', '["Declarative", "Interrogative", "Imperative", "Exclamatory"]', 0, 'Declarative: states opinion/fact. Pattern: Subject + verb + adverb + period. Makes statement.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Declarative sentences can be:', '["positive or negative", "only positive", "only negative", "only questions"]', 0, 'Declarative can be positive ("I like tea.") or negative ("I don''t like coffee."). Both make statements.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which is a statement?', '["Books are important.", "Are books important?", "Read books!", "What important books!"]', 0, 'Declarative: statement. "Books are important." = expresses opinion/fact. Pattern: Subject + verb + adjective.', 'easy'),

-- MEDIUM (12 questions)
('foundation', 'sentence-types', 'beginner', 'What is wrong? "I love chocolate"', '["Add: period at end", "Add: question mark", "Add: exclamation mark", "Nothing wrong"]', 0, 'Declarative sentence needs period. Correct: "I love chocolate." Statements must end with proper punctuation.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Choose correct: "She doesn''t like spicy food"', '["She doesn''t like spicy food.", "She doesn''t like spicy food?", "She doesn''t like spicy food!", "All correct"]', 0, 'Negative declarative statement = period. Correct: "She doesn''t like spicy food." Pattern: Negative statement + period.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Error in: "The weather is nice today?"', '["Use: period instead of ?", "Remove: ?", "Add: ! instead", "Nothing wrong"]', 0, 'Statement (not question) = period. Correct: "The weather is nice today." If not asking, use period not question mark.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Arrange: student / He / a / good / is', '["He is a good student.", "He is a good student?", "He is a good student!", "Is he a good student."]', 0, 'Declarative: statement word order. Pattern: Subject + verb + article + adjective + noun + period. Statement = period.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Which is correct declarative?', '["I think he is right.", "I think he is right?", "I think he is right!", "Think he is right."]', 0, 'Opinion statement = declarative + period. "I think..." = statement expressing opinion. No question/exclamation here.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'What is the error? "My name is Priya!"', '["Use: period instead of !", "Remove: !", "Use: ? instead", "Nothing wrong"]', 0, 'Simple statement of name = period. Correct: "My name is Priya." No strong emotion, so period not exclamation mark.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Rearrange: lives / She / Mumbai / in', '["She lives in Mumbai.", "She lives in Mumbai?", "She lives in Mumbai!", "Lives she in Mumbai."]', 0, 'Declarative: standard order. Pattern: Subject + verb + preposition + place + period. Statement = period.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Choose: "I don''t know the answer"', '["I don''t know the answer.", "I don''t know the answer?", "I don''t know the answer!", "All can work"]', 0, 'Statement of not knowing = declarative + period. Correct: "I don''t know the answer." Simple statement.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Error in: "He said he would come"', '["Add: period at end", "Add: question mark", "Add: comma after said", "Nothing wrong"]', 0, 'Missing punctuation! Declarative needs period. Correct: "He said he would come." Always end statements with period.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Which is declarative? "_____ is my favorite subject."', '["Math", "Is math", "Math, wow", "Math?"]', 0, 'Statement starts with subject. "Math is my favorite subject." = declarative. Pattern: Subject starts statement.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'What is wrong? "The meeting starts at 3 PM."', '["Nothing wrong", "Use: ?", "Use: !", "Remove: period"]', 0, 'Correct! Declarative statement with proper period. States when meeting starts. No error.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Rearrange: will / tomorrow / They / arrive', '["They will arrive tomorrow.", "They will arrive tomorrow?", "They will arrive tomorrow!", "Will they arrive tomorrow."]', 0, 'Future statement = declarative. Pattern: Subject + will + verb + time + period. Statement about future.', 'medium'),

-- HARD (6 questions)
('foundation', 'sentence-types', 'beginner', 'Which is WRONG?', '["I like tea.", "She is happy.", "He works hard?", "They are friends."]', 2, 'Statement with question mark = wrong! "He works hard?" should be "He works hard." (period) or "Does he work hard?" (question).', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Arrange: believe / I / is / the / right / answer / this', '["I believe this is the right answer.", "I believe this is the right answer?", "I believe this is the right answer!", "Both A and C"]', 0, 'Complex declarative: opinion + embedded clause. Pattern: I believe + clause + period. Statement = period only.', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Error in: "She told me she was sick"', '["Add: period at end", "Add: that after told", "Add: comma after me", "Nothing wrong"]', 0, 'Missing period! Correct: "She told me she was sick." Declarative sentences always need ending punctuation.', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Identify type: "Although it was raining, we went out."', '["Declarative (complex)", "Interrogative", "Imperative", "Exclamatory"]', 0, 'Complex declarative: makes statement with dependent clause. Still declarative despite complexity. Pattern: Dependent clause + comma + main clause + period.', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Which is correct formal writing?', '["The experiment was successful.", "The experiment was successful!", "The experiment was successful?", "Successful was the experiment."]', 0, 'Formal statement = declarative + period. No exclamation (too emotional). Standard word order. Correct: period.', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Error: "I wonder if he will come"', '["Add: period at end", "Use: ? instead", "Add: comma after wonder", "Both A acceptable"]', 0, 'Indirect question = statement = period. "I wonder..." = statement about wondering, not direct question. Correct: "I wonder if he will come." (period).', 'hard'),

-- ============================================================================
-- SUBTOPIC 2: Interrogative Sentences (30 questions)
-- ============================================================================

-- EASY (12 questions)
('foundation', 'sentence-types', 'beginner', 'Which is an interrogative sentence?', '["Do you like music?", "I like music.", "Like music!", "I love music!"]', 0, 'Interrogative sentence: asks question, ends with ?. "Do you like music?" = asks for information.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Interrogative sentences end with:', '["question mark (?)", "period (.)", "exclamation mark (!)", "comma (,)"]', 0, 'Interrogative sentences: end with question mark. Ask questions to get information. Pattern: Question + ?', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which asks a question?', '["Where are you going?", "I am going home.", "Go home!", "What a day!"]', 0, 'Interrogative: asks question. "Where are you going?" = asks for information about location/destination.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"Is she your sister?" This is:', '["Interrogative", "Declarative", "Imperative", "Exclamatory"]', 0, 'Interrogative sentence: asks yes/no question, ends with ?. Pattern: Auxiliary + subject + complement + ?', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Interrogative sentences:', '["ask questions", "make statements", "give commands", "show emotions"]', 0, 'Interrogative sentences: ask questions to get information. Use question words (what, where, when) or auxiliary verbs.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which is interrogative?', '["What is your name?", "My name is Raj.", "Tell me your name!", "What a beautiful name!"]', 0, 'Interrogative: asks question. "What is your name?" = asks for information. Pattern: Question word + auxiliary + subject + ?', 'easy'),

('foundation', 'sentence-types', 'beginner', '"Can you help me?" Type?', '["Interrogative", "Declarative", "Imperative", "Exclamatory"]', 0, 'Interrogative: asks question (requests help). Pattern: Modal + subject + verb + object + ?', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Correct punctuation for question:', '["question mark (?)", "period (.)", "exclamation mark (!)", "semicolon (;)"]', 0, 'Questions (interrogative sentences) end with question mark. Statement = period, question = ?, exclamation = !', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which asks for information?', '["When does the class start?", "The class starts at 9.", "Start the class!", "What a class!"]', 0, 'Interrogative: asks for specific information (time). Pattern: Question word + auxiliary + subject + verb + ?', 'easy'),

('foundation', 'sentence-types', 'beginner', '"Are you ready?" Type?', '["Interrogative", "Declarative", "Imperative", "Exclamatory"]', 0, 'Interrogative: yes/no question. Pattern: Auxiliary + subject + adjective + ? Asks for yes or no answer.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Question words include:', '["what, where, when, why, how", "and, but, or", "run, jump, walk", "happy, sad, angry"]', 0, 'Question words: what, where, when, why, who, which, how. Used to ask specific questions. Also called "wh-words".', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which is a question?', '["How are you?", "I am fine.", "Be fine!", "How fine you are!"]', 0, 'Interrogative: question. "How are you?" = asks about condition/state. Pattern: How + auxiliary + subject + ?', 'easy'),

-- MEDIUM (12 questions)
('foundation', 'sentence-types', 'beginner', 'What is wrong? "What is your name."', '["Use: ? instead of period", "Add: ?", "Remove: period", "All corrections needed"]', 0, 'Question needs ?. Correct: "What is your name?" Question words + question structure = question mark required.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Choose correct: "Do you speak English"', '["Do you speak English?", "Do you speak English.", "Do you speak English!", "All correct"]', 0, 'Question = question mark. Correct: "Do you speak English?" Pattern: Auxiliary + subject + verb + ?', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Error in: "Where are you going."', '["Use: ? instead of period", "Remove: period", "Add: !", "Nothing wrong"]', 0, 'Question word + question = ?. Correct: "Where are you going?" Question needs question mark not period.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Arrange: you / Are / tomorrow / free', '["Are you free tomorrow?", "Are you free tomorrow.", "You are free tomorrow?", "Are you free tomorrow!"]', 0, 'Interrogative: inverted order. Pattern: Auxiliary + subject + adjective + time + ? Yes/no question structure.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Which is correct interrogative?', '["Can you help me?", "You can help me?", "Can you help me.", "You can help me."]', 0, 'Proper interrogative: inversion + ?. "Can you help me?" = correct structure. Pattern: Modal + subject + verb + ?', 'medium'),

('foundation', 'sentence-types', 'beginner', 'What is the error? "Why he is late?"', '["Use: is he instead of he is", "Remove: ?", "Add: period", "Nothing wrong"]', 0, 'Question = inverted order. Correct: "Why is he late?" Pattern: Question word + auxiliary + subject + adjective + ?', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Rearrange: time / What / is / it', '["What time is it?", "What time is it.", "What is time it?", "What time it is?"]', 0, 'Question word order: What + noun + auxiliary + subject + ? Correct: "What time is it?" Natural question structure.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Choose: "Have you finished your work"', '["Have you finished your work?", "Have you finished your work.", "You have finished your work?", "Finished you have your work?"]', 0, 'Present perfect question: Have + subject + past participle + object + ? Correct inversion + punctuation.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Error in: "Does she knows the answer?"', '["Use: know instead of knows", "Remove: ?", "Use: s after Does", "Nothing wrong"]', 0, 'After does/did = base verb. Correct: "Does she know the answer?" Pattern: Does + subject + base verb + ?', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Which is interrogative? "_____ bought this book?"', '["Who", "He", "Buy", "Bought"]', 0, 'Question starts with question word. "Who bought this book?" = asks for subject. Pattern: Who + verb + object + ?', 'medium'),

('foundation', 'sentence-types', 'beginner', 'What is wrong? "How old are you"', '["Add: ? at end", "Add: period", "Add: !", "Nothing wrong"]', 0, 'Question needs ?. Correct: "How old are you?" Questions must end with question mark.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Rearrange: they / When / arrive / will', '["When will they arrive?", "When will they arrive.", "When they will arrive?", "Will when they arrive?"]', 0, 'Question order: Question word + will + subject + verb + ? Correct: "When will they arrive?" Future question.', 'medium'),

-- HARD (6 questions)
('foundation', 'sentence-types', 'beginner', 'Which is WRONG?', '["What is your name?", "Where do you live?", "How you are?", "Why are you late?"]', 2, 'Wrong word order! Correct: "How are you?" Pattern: How + auxiliary + subject + ? Need inversion!', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Arrange: the / Who / teacher / is / new', '["Who is the new teacher?", "Who the new teacher is?", "Who is the new teacher.", "Is who the new teacher?"]', 0, 'Subject question: Who + verb + complement + ? No inversion needed when "who" is subject. Correct: "Who is the new teacher?"', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Error in: "You are coming tomorrow?"', '["Use: Are you instead of You are", "Add period", "Remove: ?", "Nothing wrong"]', 0, 'Proper question = inversion. Correct: "Are you coming tomorrow?" Pattern: Auxiliary + subject + verb + time + ?', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Identify type: "Could you please open the door?"', '["Interrogative (polite request)", "Imperative", "Declarative", "Exclamatory"]', 0, 'Interrogative: asks politely (request in question form). Pattern: Modal + subject + please + verb + ? Still interrogative despite politeness.', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Which is correct?', '["What did you say?", "What you said?", "What did you said?", "What you did say?"]', 0, 'Past question: What + did + subject + base verb + ? Correct: "What did you say?" Pattern: did + base verb!', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Error: "I wonder what is his name?"', '["Remove: ?", "Use: what his name is", "Add: period", "Multiple issues"]', 3, 'Indirect question = no inversion + period. Correct: "I wonder what his name is." (period, not ?). Statement about wondering!', 'hard'),

-- ============================================================================
-- SUBTOPIC 3: Imperative Sentences (30 questions)
-- ============================================================================

-- EASY (12 questions)
('foundation', 'sentence-types', 'beginner', 'Which is an imperative sentence?', '["Close the door.", "I closed the door.", "Is the door closed?", "The door is closed!"]', 0, 'Imperative sentence: gives command/request, starts with verb. "Close the door." = command. Pattern: Verb + object.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Imperative sentences:', '["give commands or requests", "ask questions", "make statements", "show emotions"]', 0, 'Imperative sentences: give commands, make requests, give instructions. Subject "you" is understood but not stated.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which gives a command?', '["Sit down.", "He sat down.", "Did you sit?", "What a seat!"]', 0, 'Imperative: command. "Sit down." = tells someone to sit. Pattern: Verb (+ adverb/object). No subject needed.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"Please help me." This is:', '["Imperative", "Declarative", "Interrogative", "Exclamatory"]', 0, 'Imperative sentence: polite request. "Please" makes it polite but still imperative. Pattern: Please + verb + object.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Imperative sentences can end with:', '["period (.) or exclamation mark (!)", "only question mark (?)", "only comma (,)", "only semicolon (;)"]', 0, 'Imperative: period (polite request) or ! (strong command). "Please sit." (period) vs "Sit down!" (exclamation).', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which is imperative?', '["Open the window.", "The window is open.", "Is the window open?", "What an open window!"]', 0, 'Imperative: command. "Open the window." = tells someone to open it. Pattern: Verb + object + period.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"Be quiet!" Type?', '["Imperative", "Declarative", "Interrogative", "Exclamatory"]', 0, 'Imperative: strong command (exclamation mark shows urgency). Pattern: Verb + adjective + ! Command to be silent.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Imperative sentences start with:', '["verb (base form)", "subject pronoun", "question word", "article"]', 0, 'Imperative: starts with base verb. No subject (you is understood). Pattern: Verb + rest of sentence.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which gives instruction?', '["Turn left at the corner.", "I turned left.", "Did you turn left?", "What a turn!"]', 0, 'Imperative: instruction/direction. "Turn left..." = tells someone what to do. Pattern: Verb + direction + location.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"Listen carefully." Type?', '["Imperative", "Declarative", "Interrogative", "Exclamatory"]', 0, 'Imperative: command. "Listen carefully." = tells someone to listen. Pattern: Verb + adverb + period.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'The subject in imperative sentences is:', '["you (understood)", "I", "we", "they"]', 0, 'Imperative: subject "you" is understood but not written. "Close door" = (You) close door. Understood subject!', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which is a request?', '["Please come here.", "He came here.", "Will you come?", "How you came!"]', 0, 'Imperative: polite request. "Please come here." = asks politely. "Please" makes command polite.', 'easy'),

-- MEDIUM (12 questions)
('foundation', 'sentence-types', 'beginner', 'What is wrong? "You close the door."', '["Remove: You (use: Close the door.)", "Add: ?", "Use: closed", "Nothing wrong"]', 0, 'Imperative = no subject. Correct: "Close the door." Don''t write "you" in imperative sentences. Start with verb!', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Choose correct imperative:', '["Stop!", "You stop!", "He stops.", "Stopping!"]', 0, 'Imperative: base verb only (no subject/pronouns). "Stop!" = correct command. Pattern: Verb + exclamation mark.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Error in: "You please sit down."', '["Remove: You", "Use: You, please,", "Add: ?", "Nothing wrong"]', 0, 'Imperative = no subject. Correct: "Please sit down." Remove "You" from imperative commands/requests.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Arrange: door / the / Close / quietly', '["Close the door quietly.", "You close the door quietly.", "Closing the door quietly.", "The door close quietly."]', 0, 'Imperative: Verb + object + adverb. Correct: "Close the door quietly." No subject needed!', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Which is correct imperative?', '["Don''t be late.", "You don''t be late.", "Not be late.", "Being not late."]', 0, 'Negative imperative: Don''t + base verb. Correct: "Don''t be late." Pattern: Don''t + verb (no subject).', 'medium'),

('foundation', 'sentence-types', 'beginner', 'What is the error? "Please you help me."', '["Remove: you", "Move: you to end", "Use: your", "Nothing wrong"]', 0, 'Imperative = no subject. Correct: "Please help me." Remove "you" from requests. Pattern: Please + verb + object.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Rearrange: me / call / Please / tomorrow', '["Please call me tomorrow.", "You please call me tomorrow.", "Please you call me tomorrow.", "Calling me please tomorrow."]', 0, 'Polite imperative: Please + verb + object + time. Correct: "Please call me tomorrow." No subject!', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Choose: Negative imperative for "run":', '["Don''t run.", "Not run.", "No run.", "You don''t run."]', 0, 'Negative imperative: Don''t + base verb. Correct: "Don''t run." Pattern: Don''t + verb (no subject).', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Error in: "Let''s we go."', '["Remove: we", "Use: us instead of we", "Remove: Let''s", "Nothing wrong"]', 0, 'Let''s already includes "us". Correct: "Let''s go." Pattern: Let''s + base verb. "Let''s" = Let us (already includes us).', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Which is imperative? "_____ your homework."', '["Do", "I do", "Doing", "Does"]', 0, 'Imperative starts with base verb. "Do your homework." = command. Pattern: Base verb + object.', 'medium'),

('foundation', 'sentence-types', 'beginner', 'What is wrong? "Stand up!"', '["Nothing wrong", "Add: You", "Remove: !", "Use: period"]', 0, 'Correct! Imperative command with exclamation (urgency). "Stand up!" = proper imperative. No error!', 'medium'),

('foundation', 'sentence-types', 'beginner', 'Rearrange: carefully / Read / the / instructions', '["Read the instructions carefully.", "You read the instructions carefully.", "Reading the instructions carefully.", "The instructions read carefully."]', 0, 'Imperative: Verb + object + adverb. Correct: "Read the instructions carefully." No subject needed!', 'medium'),

-- HARD (6 questions)
('foundation', 'sentence-types', 'beginner', 'Which is WRONG?', '["Come here.", "Please sit down.", "You go there.", "Stop!"]', 2, 'Imperative needs no subject! Wrong: "You go there." Correct: "Go there." Remove "you" from imperatives!', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Arrange: homework / the / finish / Let''s / together', '["Let''s finish the homework together.", "Let''s us finish the homework together.", "We let''s finish the homework together.", "Let''s finishing the homework together."]', 0, 'Let''s (let us) + base verb. Correct: "Let''s finish the homework together." Don''t add "us" (already in Let''s)!', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Error: "Never you do that again."', '["Remove: you", "Move: you after Never", "Use: your", "Nothing wrong"]', 0, 'Negative imperative = no subject. Correct: "Never do that again." Remove "you". Pattern: Never + base verb!', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Identify type: "Be kind to others."', '["Imperative (advice)", "Declarative", "Interrogative", "Exclamatory"]', 0, 'Imperative: advice/suggestion in command form. Pattern: Be + adjective + prepositional phrase. Still imperative despite gentle tone.', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Which is correct?', '["Always tell the truth.", "You always tell the truth.", "Always telling the truth.", "Tell always the truth."]', 0, 'Imperative: adverb + verb + object. Correct: "Always tell the truth." No subject, adverb can start sentence.', 'hard'),

('foundation', 'sentence-types', 'beginner', 'Error: "Don''t you worry."', '["Remove: you (use: Don''t worry.)", "Nothing wrong (emphasis)", "Both correct", "Remove: Don''t"]', 2, 'Both acceptable! "Don''t worry." (standard). "Don''t you worry." (emphasis, colloquial). Context: both grammatically valid!', 'hard'),

-- ============================================================================
-- SUBTOPIC 4: Exclamatory Sentences (30 questions)
-- ============================================================================

-- EASY (12 questions)
('foundation', 'sentence-types', 'beginner', 'Which is an exclamatory sentence?', '["What a beautiful day!", "Today is beautiful.", "Is today beautiful?", "Make it beautiful."]', 0, 'Exclamatory sentence: shows strong emotion, ends with !. "What a beautiful day!" = expresses joy/surprise.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Exclamatory sentences end with:', '["exclamation mark (!)", "period (.)", "question mark (?)", "comma (,)"]', 0, 'Exclamatory sentences: end with exclamation mark. Show strong emotion (joy, surprise, anger, excitement).', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which shows strong emotion?', '["How wonderful!", "It is wonderful.", "Is it wonderful?", "Be wonderful."]', 0, 'Exclamatory: strong emotion. "How wonderful!" = expresses great joy. Pattern: How + adjective + !', 'easy'),

('foundation', 'sentence-types', 'beginner', '"What a surprise!" This is:', '["Exclamatory", "Declarative", "Interrogative", "Imperative"]', 0, 'Exclamatory sentence: expresses surprise, ends with !. Pattern: What + article + noun + !', 'easy'),

