('foundation', 'sentence-types', 'beginner', 'Which is exclamatory?', '["How beautiful you are!", "You are beautiful.", "Are you beautiful?", "Be beautiful."]', 0, 'Exclamatory: strong emotion (admiration). "How beautiful you are!" = expresses amazement. Pattern: How + adjective + subject + verb + !', 'easy'),

('foundation', 'sentence-types', 'beginner', '"Wow! That''s amazing!" Type?', '["Exclamatory", "Declarative", "Interrogative", "Imperative"]', 0, 'Exclamatory: shows excitement/amazement. Interjection + exclamation. Pattern: Interjection + ! + Statement + !', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Exclamatory sentences often start with:', '["What or How", "Who or Where", "If or Because", "And or But"]', 0, 'Exclamatory: often start with "What" or "How". Pattern: What a...! / How...! Express strong feelings.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Which expresses joy?', '["I am so happy!", "I am happy.", "Am I happy?", "Be happy."]', 0, 'Exclamatory: shows strong joy. "I am so happy!" = exclamation mark shows intensity of emotion.', 'easy'),

('foundation', 'sentence-types', 'beginner', '"How fast he runs!" Type?', '["Exclamatory", "Declarative", "Interrogative", "Imperative"]', 0, 'Exclamatory: expresses amazement about speed. Pattern: How + adverb + subject + verb + ! Shows strong emotion.', 'easy'),

('foundation', 'sentence-types', 'beginner', 'Correct punctuation for exclamation:', '["exclamation mark (!)", "period (.)", "question mark (?)", "semicolon (;)"]', 0, 'Exclamations end with !. Shows strong emotion. Statement = period, question = ?, exclamation = !', 'easy'),

